  user-select: none;
}

.draggable:active { cursor: grabbing; opacity: 0.6; }

/* ============================================================
   RESIZE OBSERVER DEMO
============================================================ */
.resize-demo {
  resize: horizontal;
  overflow: hidden;
  min-width: 200px;
  max-width: 100%;
  background: var(--bg3);
  border: 1px solid var(--border);
  padding: 1rem;
  font-size: 0.75rem;
  color: var(--muted);
}

#resize-info { color: var(--b); font-size: 0.7rem; margin-top: 4px; }

