  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
}

.io-box {
  width: 100px;
  height: 60px;
  background: var(--bg3);
  border: 1px solid var(--border);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.65rem;
  color: var(--muted);
  transition: border-color 0.3s, background 0.3s;
}

.io-box.visible {
  border-color: var(--a);
  background: rgba(232,255,106,0.05);
  color: var(--a);
}

/* ============================================================
   CANVAS
============================================================ */
#main-canvas {
  width: 100%;
  height: 200px;
  display: block;
  cursor: crosshair;
}

/* ============================================================
   INPUT EVENTS
============================================================ */
.input-events-demo {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
}

.ied-box {
  background: var(--bg3);
  border: 1px solid var(--border);
  padding: 1rem;
  font-size: 0.75rem;
  color: var(--muted);
  min-height: 80px;
  display: flex;
  flex-direction: column;
