}

.ied-val { color: var(--a); font-variant-numeric: tabular-nums; }

/* ============================================================
   MISC
============================================================ */
.marquee-wrap {
  overflow: hidden;
  white-space: nowrap;
  border: 1px solid var(--border);
  background: var(--bg3);
  height: 36px;
  display: flex;
  align-items: center;
}

.marquee-inner {
  display: inline-block;
  animation: marquee 12s linear infinite;
  font-size: 0.75rem;
  color: var(--muted);
  padding-left: 100%;
}

.marquee-inner span { color: var(--a); margin: 0 16px; }

.typewriter-line {
  overflow: hidden;
  white-space: nowrap;
  border-right: 2px solid var(--a);
  font-size: 0.875rem;
  color: var(--a);
  width: 0;
  animation: typewriter 3s steps(40) 0.5s forwards, blink 0.75s step-end infinite;
}

/* ============================================================
   MEDIA QUERIES
============================================================ */
@media (max-width: 768px) {
  .page { grid-template-columns: 1fr; }
  #sidebar { display: none; }
  .form-demo { grid-template-columns: 1fr; }
  .overflow-demos { grid-template-columns: 1fr; }
  .input-events-demo { grid-template-columns: 1fr; }
}

@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    transition-duration: 0.01ms !important;
  }
}

@media print {
  body { background: white; color: black; }
  #sidebar, #header, .anim-grid { display: none; }
}

/* container queries (pokud je podporovano) */
.cq-container {
  container-type: inline-size;
  container-name: card-cq;
  background: var(--bg3);
  border: 1px solid var(--border);
  padding: 1rem;
  resize: horizontal;
  overflow: hidden;
  min-width: 200px;
  max-width: 100%;
}

